import Button from "./Button";
import styles from "./App.module.css";
import { useState, useEffect } from "react";

function App() {
  const [toDo, setToDo] = useState("");
  const onChange = (event) => setToDo(event.target.value);
  return (
    <div>
      <form></form>
      <input
        value={toDo}
        onChange={onChange}
        type="text"
        placeholder="Write your ToDo"
      ></input>
    </div>
  );
}

export default App;
